#include <stdio.h>
#include <stdint.h>
#include <string.h>

// The entry point generated by the Autarky LLVM Backend
extern uint64_t autarky_main();

int main() {
    // Execute the native machine code
    uint64_t raw_result = autarky_main();
    
    // Safely bitcast the 64-bit integer into a 64-bit float (double)
    double float_result;
    memcpy(&float_result, &raw_result, sizeof(double));
    
    printf("🎉 NATIVE EXECUTION SUCCESSFUL!\n");
    // We print both interpretations since the C runtime doesn't know 
    // which type the Autarky program evaluated to!
    printf("FINAL RESULT (If Int): %llu\n", raw_result);
    printf("FINAL RESULT (If Float): %f\n", float_result);
    printf("=====================================\n");
    
    return 0;
}